const calculateNextWorkingSaturday = (
  currentDate: Date,
  frequency: number,
  lastWorkingSaturday: Date
): Date => {
  const daysSinceLastSaturday = Math.floor(
    (currentDate.getTime() - lastWorkingSaturday.getTime()) / (1000 * 60 * 60 * 24)
  );

  const weeksSinceLastSaturday = Math.floor(daysSinceLastSaturday / 7);
  const weeksUntilNext = frequency - (weeksSinceLastSaturday % frequency);

  const nextSaturday = new Date(lastWorkingSaturday);
  nextSaturday.setDate(nextSaturday.getDate() + (weeksUntilNext * 7));

  return nextSaturday;
};
```

